/**
 * MedX opacity theme token runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Opacity levels for disabled and overlay states.
 */
const OPACITY_TOKENS = Object.freeze({
  primary: { value: "theme-opacity-primary", scope: "theme" },
  secondary: { value: "theme-opacity-secondary", scope: "theme" },
  muted: { value: "theme-opacity-muted", scope: "theme" },
  accent: { value: "theme-opacity-accent", scope: "theme" },
  surface: { value: "theme-opacity-surface", scope: "theme" },
});

const OPACITY_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const OPACITY_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const opacityRegistry = new Map();
const OPACITY_listeners = new Set();
let OPACITY_seq = 0;

function createOpacityId(prefix = "medx-theme-opacity") {
  OPACITY_seq += 1;
  return `${prefix}-${OPACITY_seq}`;
}

function registerOpacity(config = {}) {
  const entryId = config.id ?? createOpacityId();
  const preset = OPACITY_PRESETS[config.preset ?? "default"] ?? OPACITY_PRESETS.default;
  const token = OPACITY_TOKENS[config.token ?? preset.token] ?? OPACITY_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: OPACITY_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  opacityRegistry.set(entryId, entry);
  notifyOpacityListeners("register", entry);
  return entry;
}

function updateOpacity(id, patch = {}) {
  const entry = opacityRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyOpacityListeners("update", entry);
  return entry;
}

function resolveOpacity(id) {
  const entry = opacityRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listOpacityEntries(filter = {}) {
  let items = Array.from(opacityRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onOpacityEvent(listener) {
  OPACITY_listeners.add(listener);
  return () => OPACITY_listeners.delete(listener);
}

function notifyOpacityListeners(type, entry) {
  for (const listener of OPACITY_listeners) {
    try {
      listener({ type, entry, registrySize: opacityRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:theme:opacity] listener error", err.message);
    }
  }
}

function getOpacityMetrics() {
  const items = listOpacityEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(OPACITY_TOKENS).length,
    presets: Object.keys(OPACITY_PRESETS).length,
  };
}

async function runMedxOpacity() {
  console.log("[medx:ui:theme:opacity] runtime initialized");
  console.log(`[medx:ui:theme:opacity] tokens=${Object.keys(OPACITY_TOKENS).length} presets=${Object.keys(OPACITY_PRESETS).length}`);

  const events = [];
  onOpacityEvent((e) => events.push(e.type));

  const domains = Object.keys(OPACITY_SUPPLY_CHAIN);
  const presets = Object.keys(OPACITY_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerOpacity({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "theme/opacity" },
    });
  }

  const first = listOpacityEntries()[0];
  if (first) updateOpacity(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getOpacityMetrics();
  const resolved = first ? resolveOpacity(first.id) : null;

  console.log(`[medx:ui:theme:opacity] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:theme:opacity] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:theme:opacity] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:theme:opacity] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:theme:opacity] bootstrap complete");
}

module.exports = runMedxOpacity;
